#include <stdio.h>
int main() {
    int T, N, x, y, max_x = 0, max_y = 0;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        max_x = max_y = 0;
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &x, &y);
            max_x = (max_x > x) ? max_x : x;
            max_y = (max_y > y) ? max_y : y;
        }
        printf("%d\n", (max_x > max_y) ? max_x : max_y);
    }
    return 0;
}

