code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int max_x = 0, max_y = 0;
            for (int i = 0; i < N; i++) {
                int x = scanner.nextInt();
                int y = scanner.nextInt();
                max_x = Math.max(max_x, x);
                max_y = Math.max(max_y, y);
            }
            System.out.println(Math.max(max_x, max_y));
        }
    }
}

code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let T;
let input = [];
readline.on('line', line => {
    if (i === 0) {
        T = parseInt(line);
    } else {
        input.push(line);
    }
    i++;
    if (i === T * 2 + 1) {
        for (let j = 0; j < T; j++) {
            let N = parseInt(input[j * 2]);
            let max_x = max_y = 0;
            let points = input[j * 2 + 1].split(' ');
            for (let k = 0; k < N * 2; k += 2) {
                let x = parseInt(points[k]);
                let y = parseInt(points[k + 1]);
                max_x = Math.max(max_x, x);
                max_y = Math.max(max_y, y);
            }
            console.log(Math.max(max_x, max_y));
        }
    }
});
